select min(ss.slot_id) as slot_id, min(ss.schedule_id) as schedule_id, ss.doctor_id, d.dept_id, sd.dept_name, d.doctor_name, d.level_id, rl.level_name, rl.fee, ss.schedule_date, min(date_format(ss.start_time, '%H:%i')) as start_time, max(date_format(ss.end_time, '%H:%i')) as end_time, sum(ss.max_number) as max_number, sum(ss.reserved_number) as reserved_number, sum(greatest(ifnull(ss.max_number, 0) - ifnull(ss.reserved_number, 0), 0)) as available_number, '0' as status, null as create_time, null as update_time from schedule_slot ss inner join doctor d on d.doctor_id = ss.doctor_id left join sys_dept sd on sd.dept_id = d.dept_id left join regist_level rl on rl.level_id = d.level_id
ss.status = '0' and ss.reserved_number < ss.max_number and ss.doctor_id = #{doctorId} and d.dept_id = #{deptId} and exists (select 1 from sys_user_role ur where ur.user_id = d.user_id and ur.role_id = #{roleId}) and ss.schedule_date = #{scheduleDate} and ss.schedule_date >= #{beginDate} and ss.schedule_date <= #{endDate}
group by ss.doctor_id, d.dept_id, sd.dept_name, d.doctor_name, d.level_id, rl.level_name, rl.fee, ss.schedule_date order by ss.schedule_date, d.level_id desc, d.doctor_id

